(window.webpackJsonp=window.webpackJsonp||[]).push([[91],{718:function(n,e){n.exports='\x3c!-- \ntitle: 12-Vue3入门\nsort: \n--\x3e \n\n## 新东西\n\n```vue\n<template>\n  <div id="app">\n    <h2>{{ name }}</h2>\n    <p>{{ age }}</p>\n    <p>{{ increase }}</p>\n    <button @click="addAge()">Age++</button>\n    <button @click="stopWatch()">StopWatch</button>\n  </div>\n</template>\n  \n<script>\nimport { ref, toRefs, watch, onMounted, reactive } from "vue";\nexport default {\n  setup() {\n    // ref创建一个响应式的数据对象\n    const name = ref("fzf");\n    const age = ref(18);\n    const increase = ref(0);\n\n    // 使用reactive创建复杂数据类型\n    // 读取时无需.value\n    const user = reactive({ name: "fzf", age: age });\n\n    // 增加年龄\n    function addAge() {\n      age.value++; // 改变或获取值使用.value\n    }\n\n    // 使用watch监听age修改\n    function addIncrease() {\n      increase.value++;\n    }\n    // 调用返回值可停止watch\n    const stopWatch = watch(age, addIncrease);\n\n    // 在 `mounted` 时调用 ` addAge`\n    onMounted(addAge);\n\n    // 返回后模板中可使用\n    return {\n      // 解构user\n      ...toRefs(user),\n      increase,\n      addAge,\n      stopWatch,\n    };\n  },\n};\n<\/script>\n```\n\n'}}]);